                          { mode: 'classic' as GameMode, icon: Target, label: 'Cß╗ò ─æiß╗ân', desc: 'Chß╗ìn ─æ├íp ├ín ─æ├║ng', gradient: 'from-rose-50 to-pink-50', border: 'border-rose-200 hover:border-rose-400', iconColor: 'text-rose-500' },
                          { mode: 'speed' as GameMode, icon: Zap, label: 'Tß╗æc ─æß╗Ö', desc: 'Trß║ú lß╗¥i nhanh', gradient: 'from-pink-50 to-rose-50', border: 'border-pink-200 hover:border-pink-400', iconColor: 'text-pink-500' },
                          { mode: 'listening' as GameMode, icon: Headphones, label: 'Nghe', desc: 'Nghe v├á chß╗ìn', gradient: 'from-rose-50 to-pink-50', border: 'border-rose-200 hover:border-rose-400', iconColor: 'text-rose-400' },
                          { mode: 'writing' as GameMode, icon: PenTool, label: 'Viß║┐t', desc: 'G├╡ reading', gradient: 'from-pink-50 to-rose-50', border: 'border-pink-200 hover:border-pink-400', iconColor: 'text-pink-400' },
                          { mode: 'pronunciation' as GameMode, icon: Mic, label: 'Ph├ít ├óm', desc: 'Luyß╗çn n├│i tß╗½', gradient: 'from-rose-50 to-pink-50', border: 'border-sakura/20 hover:border-sakura', iconColor: 'text-sakura' },
                        ]).map(({ mode, icon: Icon, label, desc, gradient, border, iconColor }) => (
                          <motion.div key={mode} whileHover={{ scale: 1.05, y: -4 }} whileTap={{ scale: 0.95 }}>
                            <Card
                              className={cn('cursor-pointer transition-all duration-200 hover:shadow-md', `bg-gradient-to-br ${gradient} ${border} border`)}
                              onClick={() => { if (words.length >= 4) setActiveGame(mode); }}
                            >
                              <CardContent className="p-4 text-center space-y-2">
                                <Icon className={cn('h-6 w-6 mx-auto', iconColor)} />
                                <p className="text-sm font-bold">{label}</p>
                                <p className="text-[10px] text-muted-foreground">{desc}</p>
                              </CardContent>
                            </Card>
                          </motion.div>
                        ))}
                      </div>
                      {words.length < 4 && <p className="text-xs text-center text-rose-400">Cß║ºn ├¡t nhß║Ñt 4 tß╗½ ─æß╗â ├┤n tß║¡p</p>}
                    </CardContent>
                  </Card>
                </motion.div>
              )}
            </AnimatePresence>
          </>
        ) : (
          <Card className="border-rose-200 border-dashed border-2">
            <CardContent className="p-8 text-center space-y-3">
              <FolderOpen className="h-12 w-12 text-rose-300 mx-auto" />
              <p className="text-muted-foreground">Ch╞░a c├│ tß╗½ n├áo. Th├¬m tß╗½ hoß║╖c import ─æß╗â bß║»t ─æß║ºu!</p>
            </CardContent>
          </Card>
        )}

        {/* Word List */}
        {words.length > 0 && (
          <div className="space-y-4">
            <h3 className="font-bold text-lg">Danh s├ích tß╗½ ({words.length})</h3>
            <div className="space-y-2">
              {words.map((word, idx) => (
                <motion.div key={word.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: idx * 0.015 }}>
