                  </button>
                  <button
                    className={cn('px-4 py-2 rounded-xl text-sm font-medium flex items-center gap-2 transition-all', importTab === 'json' ? 'bg-rose-100 text-rose-700 ring-2 ring-rose-300' : 'bg-muted hover:bg-rose-50')}
                    onClick={() => { setImportTab('json'); setImportPreview(null); setImportError(''); }}
                  >
                    <FileJson className="h-4 w-4" /> JSON
                  </button>
                </div>

                {/* Format Guide */}
                <div className="bg-rose-50/50 rounded-xl p-4 border border-rose-100">
                  <p className="text-sm font-bold text-rose-700 mb-2">≡ƒôï H╞░ß╗¢ng dß║½n format ({importTab === 'excel' ? 'Excel' : 'JSON'})</p>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                      <thead>
                        <tr className="bg-rose-100/50">
                          <th className="px-3 py-2 text-left font-bold text-rose-700">{importTab === 'excel' ? 'Cß╗Öt' : 'Key'}</th>
                          <th className="px-3 py-2 text-left text-rose-700">M├┤ tß║ú</th>
                          <th className="px-3 py-2 text-left text-rose-700">V├¡ dß╗Ñ</th>
                          <th className="px-3 py-2 text-center text-rose-700">Bß║»t buß╗Öc</th>
                        </tr>
                      </thead>
                      <tbody>
                        <tr className="border-t border-rose-100"><td className="px-3 py-1.5 font-mono text-xs">word</td><td className="px-3 py-1.5">Tß╗½ tiß║┐ng Nhß║¡t</td><td className="px-3 py-1.5 font-jp">σ¡ªµáí</td><td className="px-3 py-1.5 text-center text-green-600">Γ£à</td></tr>
                        <tr className="border-t border-rose-100"><td className="px-3 py-1.5 font-mono text-xs">reading</td><td className="px-3 py-1.5">C├ích ─æß╗ìc</td><td className="px-3 py-1.5 font-jp">πüîπüúπüôπüå</td><td className="px-3 py-1.5 text-center text-muted-foreground">ΓÇö</td></tr>
                        <tr className="border-t border-rose-100"><td className="px-3 py-1.5 font-mono text-xs">hanviet</td><td className="px-3 py-1.5">H├ín Viß╗çt</td><td className="px-3 py-1.5">Hß╗ìc Hiß╗çu</td><td className="px-3 py-1.5 text-center text-muted-foreground">ΓÇö</td></tr>
                        <tr className="border-t border-rose-100"><td className="px-3 py-1.5 font-mono text-xs">meaning</td><td className="px-3 py-1.5">Ngh─⌐a tiß║┐ng Viß╗çt</td><td className="px-3 py-1.5">Tr╞░ß╗¥ng hß╗ìc</td><td className="px-3 py-1.5 text-center text-green-600">Γ£à</td></tr>
                      </tbody>
                    </table>
                  </div>
                </div>

                {/* Excel tab */}
                {importTab === 'excel' && (
                  <div className="space-y-3">
                    <div className="flex gap-3">
                      <Button variant="outline" size="sm" className="gap-2 border-rose-200 text-rose-600" onClick={downloadTemplate}>
                        <Download className="h-4 w-4" /> Tß║úi file mß║½u (.xlsx)
                      </Button>
                      <Button size="sm" className="gap-2 bg-gradient-to-r from-rose-400 to-pink-400 text-white" onClick={() => fileInputRef.current?.click()}>
                        <Upload className="h-4 w-4" /> Chß╗ìn file Excel
                      </Button>
                      <input ref={fileInputRef} type="file" accept=".xlsx,.xls" onChange={handleExcelUpload} className="hidden" />
                    </div>
                  </div>
                )}

                {/* JSON tab */}
                {importTab === 'json' && (
                  <div className="space-y-3">
                    <textarea
                      value={jsonInput}
                      onChange={(e) => setJsonInput(e.target.value)}
                      placeholder={'[\n  { "word": "σ¡ªµáí", "reading": "πüîπüúπüôπüå", "hanviet": "Hß╗ìc Hiß╗çu", "meaning": "Tr╞░ß╗¥ng hß╗ìc" }\n]'}
                      className="w-full h-40 px-4 py-3 rounded-xl border border-rose-200 focus:ring-2 focus:ring-rose-300 outline-none text-sm font-mono bg-background resize-none"
                    />
                    <Button size="sm" className="gap-2 bg-gradient-to-r from-rose-400 to-pink-400 text-white" onClick={() => { const w = parseJsonImport(jsonInput); if (w) setImportPreview(w); }}>
                      <Eye className="h-4 w-4" /> Preview
                    </Button>
                  </div>
                )}

                {/* Error */}
                {importError && (
                  <div className="bg-red-50 text-red-600 rounded-xl p-3 text-sm whitespace-pre-wrap border border-red-200">{importError}</div>
                )}

                {/* Preview */}
                {importPreview && importPreview.length > 0 && (
                  <div className="space-y-3">
                    <p className="text-sm font-bold text-green-600">Γ£à {importPreview.length} tß╗½ sß║╡n s├áng import</p>
                    <div className="max-h-48 overflow-y-auto rounded-xl border border-rose-100">
                      <table className="w-full text-sm">
                        <thead className="bg-rose-50 sticky top-0">
                          <tr>
                            <th className="px-3 py-2 text-left">#</th>
                            <th className="px-3 py-2 text-left">word</th>
                            <th className="px-3 py-2 text-left">reading</th>
                            <th className="px-3 py-2 text-left">hanviet</th>
                            <th className="px-3 py-2 text-left">meaning</th>
                          </tr>
                        </thead>
                        <tbody>
                          {importPreview.map((w, i) => (
                            <tr key={i} className="border-t border-rose-50">
                              <td className="px-3 py-1.5 text-muted-foreground">{i + 1}</td>
                              <td className="px-3 py-1.5 font-jp">{w.word}</td>
                              <td className="px-3 py-1.5 font-jp">{w.reading}</td>
                              <td className="px-3 py-1.5">{w.hanviet}</td>
                              <td className="px-3 py-1.5">{w.meaning}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                    <div className="flex gap-3 justify-end">
                      <Button variant="ghost" onClick={() => { setImportPreview(null); setJsonInput(''); }}>Hß╗ºy</Button>
                      <Button className="bg-gradient-to-r from-rose-400 to-pink-400 text-white gap-2" onClick={confirmImport}>
                        <CheckCircle2 className="h-4 w-4" /> Import {importPreview.length} tß╗½
                      </Button>
                    </div>
                  </div>
                )}
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    );
  };

  return (
    <div className="min-h-screen bg-background pb-20 md:pb-0">
      <Navigation />
      <main className="container py-6 max-w-4xl">
        {showKanji ? (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-4">
            <Button
              variant="outline" size="sm"
              className="gap-2 border-emerald-300 text-emerald-600 hover:bg-emerald-50"
              onClick={() => setShowKanji(false)}
            >
              <RefreshCcw className="h-4 w-4" />
              Chuyß╗ân chß║┐ ─æß╗Ö hß╗ìc Tß╗½ vß╗▒ng
            </Button>
            <KanjiReview onBack={() => setShowKanji(false)} />
          </motion.div>
        ) : (
          <AnimatePresence mode="wait">
            {view === 'series' && renderSeries()}
            {view === 'lessons' && renderLessons()}
            {view === 'detail' && renderDetail()}
            {view === 'custom-detail' && renderCustomDetail()}
          </AnimatePresence>
        )}
      </main>
    </div>
  );
};

